// Decodificar e transformar dados
const input = $input.first().json;
let data;

try {
  data = input.data?.source?.itens;
  if (!data || !Array.isArray(data)) {
    throw new Error('Dados inválidos: esperado array em data.source.itens');
  }
} catch (error) {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    route: 'sales_nf_report',
    event: 'validation_error',
    message: error.message,
    level: 'error'
  }));
  return {
    statusCode: 400,
    body: { ok: false, error: 'Dados inválidos', details: error.message }
  };
}

// Transformar e validar cada item
const transformed = data.map(item => {
  // Função para formatar datas do timestamp
  const formatDate = (timestamp) => {
    if (!timestamp) return null;
    try {
      const date = new Date(parseInt(timestamp) * 1000);
      return date.toISOString().split('T')[0] + ' ' + date.toTimeString().split(' ')[0];
    } catch {
      return null;
    }
  };

  // Função para limpar valores monetários
  const parseDecimal = (value) => {
    if (!value) return '0.00';
    let str = value.toString();
    if (str.includes(',') && str.includes('.')) {
      str = str.replace(/\./g, '').replace(',', '.');
    } else if (str.includes(',')) {
      str = str.replace(',', '.');
    }
    return parseFloat(str).toFixed(2);
  };

  // Enriquecimento com centro de custos (simulado - baseado em ObservacoesInternas)
  let ccRef = '-1';
  if (item.ObservacoesInternas) {
    // Simples extração de centro de custo das observações
    const ccMatch = item.ObservacoesInternas.match(/CC[:\s]*([A-Z0-9]+)/i);
    if (ccMatch) {
      ccRef = ccMatch[1];
    }
  }

  return {
    ID: item.ID || '',
    Nota: item.Nota || '',
    Cliente: item.Cliente || '',
    CNPJ: item.CNPJ || '',
    Endereco: item.Endereco || '',
    Numero: item.Numero || '',
    Complemento: item.Complemento || '',
    Bairro: item.Bairro || '',
    Cidade: item.Cidade || '',
    Estado: item.Estado || '',
    CEP: item.CEP || '',
    Email: item.Email || '',
    Telefone: item.Telefone || '',
    Vendedor: item.Vendedor || '',
    ValorProdutos: parseDecimal(item.ValorProdutos),
    ValorDesconto: parseDecimal(item.ValorDesconto),
    ValorFrete: parseDecimal(item.ValorFrete),
    ValorTotal: parseDecimal(item.ValorTotal),
    TotalUnidades: item.TotalUnidades || '0',
    TotalParcelas: item.TotalParcelas || '0',
    ValorICMS: parseDecimal(item.ValorICMS),
    ValorIPI: parseDecimal(item.ValorIPI),
    ValorST: parseDecimal(item.ValorST),
    PesoBruto: parseDecimal(item.PesoBruto),
    PesoLiquido: parseDecimal(item.PesoLiquido),
    Transportadora: item.Transportadora || '',
    QtdeProdutos: item.QtdeProdutos || '0',
    CFOP: item.CFOP || '',
    Natureza: item.Natureza || '',
    Contas: item.Contas || '',
    Estoque: item.Estoque || '',
    Comissao: item.Comissao || '',
    Chave: item.Chave || '',
    Protocolo: item.Protocolo || '',
    DataPedido: formatDate(item.DataPedido),
    DataEmissao: formatDate(item.DataEmissao),
    DataAutorizacao: formatDate(item.DataAutorizacao),
    DataCad: formatDate(item.DataCad),
    DataMod: formatDate(item.DataMod),
    DataCancelamento: formatDate(item.DataCancelamento),
    Situacao: item.Situacao || '',
    Observacoes: item.Observacoes || '',
    ObservacoesInternas: item.ObservacoesInternas || '',
    CategoriaFinanceira: item.CategoriaFinanceira || '',
    Volumes: item.Volumes || '',
    EmitidoPor: item.EmitidoPor || '',
    CanceladoPor: item.CanceladoPor || '',
    cc_ref: ccRef
  };
});

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'sales_nf_report',
  event: 'data_transform_success',
  count: transformed.length,
  level: 'info'
}));

return { transformed };

// Sucesso
const result = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'sales_nf_report',
  event: 'upsert_success',
  affected_rows: result.affectedRows || 0,
  level: 'info'
}));

return {
  statusCode: 201,
  body: { ok: true, message: 'Sales NF report processed successfully' }
};

// Erro de banco
const errData = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'sales_nf_report',
  event: 'db_error',
  message: errData.message || 'Unknown DB error',
  level: 'error'
}));

return {
  statusCode: 500,
  body: { ok: false, error: 'Database error', message: 'Could not process sales NF report' }
};
